parameters.jsCode:
// Parse OpenAI response and extract intent + reply
const input = $input.item.json;
const webhookData = $('Webhook: AI Reply').item.json;

let aiResponse;
try {
  const content = input.choices[0].message.content;
  // Try to parse JSON from response (handle markdown code blocks)
  let jsonStr = content;
  if (content.includes('```')) {
    jsonStr = content.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  }
  aiResponse = JSON.parse(jsonStr);
} catch (e) {
  // Fallback if parsing fails
  aiResponse = {
    intent: 'consultation',
    reply: 'Спасибо за ваш комментарий! Напишите нам в личные сообщения для подробной консультации.',
    product: '',
    details: ''
  };
}

return [{
  json: {
    intent: aiResponse.intent || 'consultation',
    reply: aiResponse.reply || '',
    product: aiResponse.product || '',
    details: aiResponse.details || '',
    comment_id: webhookData.comment_id,
    from_id: webhookData.from_id,
    post_id: webhookData.post_id,
    text: webhookData.text,
    date: webhookData.date
  }
}];

// Prepare BlueSales customer data
const data = $input.item.json;

return [{
  json: {
    vkId: String(data.from_id),
    firstName: 'VK_' + data.from_id,
    source: 'VK комментарий',
    tags: [{ name: 'AI-сделка' }],
    comment: 'Автоматическая сделка из VK комментария: ' + data.text,
    product: data.product,
    details: data.details,
    reply: data.reply,
    post_id: data.post_id,
    comment_id: data.comment_id,
    from_id: data.from_id
  }
}];

